// ═══════════════════════════════════════
// UTILS
// ═══════════════════════════════════════
function modVal(v){ const m=Math.floor((v-10)/2); return (m>=0?'+':'')+m; }
function profBonus(level){ if(level>=17)return 6;if(level>=13)return 5;if(level>=9)return 4;if(level>=5)return 3;return 2; }
function effectiveStat(stat){
  const base=pc.base_stats[stat]||10;
  const racial=(pc.race?.bonus?.[stat])||0;
  return base+racial;
}
function errEl(id){ return document.getElementById(id); }
function setErr(id,msg){ const e=errEl(id); if(e) e.textContent=msg; }
function clearErr(id){ const e=errEl(id); if(e) e.textContent=''; }

// ═══════════════════════════════════════
// NAVIGATION
// ═══════════════════════════════════════
function goStep(n){
  if(n<1||n>7) return;
  if(n>currentStep && !validateStep(currentStep)) return;
  document.querySelectorAll('.step-panel').forEach((p,i)=>p.classList.toggle('active',i===n-1));
  document.querySelectorAll('.step-item').forEach((s,i)=>{
    s.classList.toggle('active',i===n-1);
    s.classList.toggle('done',i<n-1);
  });
  currentStep=n;
  document.getElementById('btn-prev').style.display = n>1?'inline-flex':'none';
  document.getElementById('btn-next').style.display = n<7?'inline-flex':'none';
  document.getElementById('btn-save').style.display = n===7?'inline-flex':'none';
  if(n===2) renderRaceGrid();
  if(n===3) renderClassGrid();
  if(n===4) renderBgGrid();
  if(n===5) renderStats();
  if(n===6) renderSkills();
  if(n===7) renderSummary();
  updatePreview();
  window.scrollTo({top:0,behavior:'smooth'});
}

function nextStep(){ goStep(currentStep+1); }
function prevStep(){ goStep(currentStep-1); }
function goBack(){
  if(history.length>1) history.back();
  else window.location.href='login.html';
}

function validateStep(n){
  clearErr('err-'+n);
  if(n===1){
    if(!document.getElementById('pc-name').value.trim()){
      setErr('err-1','El nombre del personaje es obligatorio.'); return false;
    }
    pc.nombre   = document.getElementById('pc-name').value.trim();
    pc.nivel    = +document.getElementById('pc-level').value||1;
    pc.age      = document.getElementById('pc-age').value;
    pc.gender   = document.getElementById('pc-gender').value;
    pc.appearance=document.getElementById('pc-appearance').value;
    pc.backstory= document.getElementById('pc-backstory').value;
    pc.xp       = XP_TABLE[pc.nivel-1]||0;
    return true;
  }
  if(n===2){ if(!pc.race){ setErr('err-2','Selecciona una raza.'); return false; } return true; }
  if(n===3){ if(!pc.class_){ setErr('err-3','Selecciona una clase.'); return false; } return true; }
  if(n===4){ if(!pc.background){ setErr('err-4','Selecciona un trasfondo.'); return false; } return true; }
  if(n===5){
    const total = STATS.reduce((s,k)=>s+pc.base_stats[k],0);
    if(total<60){ setErr('err-5','Asigna todos los atributos.'); return false; }
    computeDerived(); return true;
  }
  if(n===6){ return true; }
  return true;
}

