// ═══════════════════════════════════════
// STEP 2 — RACE
// ═══════════════════════════════════════
function filterRaces(){
  const q=document.getElementById('race-search').value.toLowerCase();
  renderRaceGrid(q);
}

function renderRaceGrid(q=''){
  if(!CC_DATA) return;
  const el=document.getElementById('race-grid'); if(!el) return;
  const races=CC_DATA.races.filter(r=>!q||r.n.toLowerCase().includes(q));
  el.innerHTML=races.map((r,i)=>{
    const bonuses=Object.entries(r.bonus||{}).map(([k,v])=>`${k} +${v}`).join(', ');
    return `<div class="sel-card${pc.race?.n===r.n?' selected':''}" onclick="selectRace(${CC_DATA.races.indexOf(r)})">
      <div class="sel-card-name">${r.n}</div>
      <div class="sel-card-sub">Vel. ${r.spd}ft</div>
      ${bonuses?`<div class="sel-card-badge">${bonuses}</div>`:''}
    </div>`;
  }).join('');
}

function selectRace(i){
  pc.race=CC_DATA.races[i];
  renderRaceGrid(document.getElementById('race-search')?.value||'');
  const el=document.getElementById('race-detail');
  const r=pc.race;
  const bonuses=Object.entries(r.bonus||{}).map(([k,v])=>`<span class="chip chip-gold">${STAT_NAMES[k]||k} +${v}</span>`).join('');
  el.innerHTML=`<h3>${r.n}</h3>
    <div class="bonus-chips">${bonuses||'<span class="chip chip-purple">Sin bonificadores de atributo</span>'}</div>
    <div style="margin-top:10px;font-size:13px;color:var(--cream-m)">Velocidad: ${r.spd}ft · Tamaño: ${r.sz||'M'}</div>
    ${r.lng?`<div style="font-size:12px;color:var(--cream-m);margin-top:4px">Idiomas: ${r.lng}</div>`:''}
    <div class="section-divider" style="margin:12px 0"></div>
    <div class="trait-list">${(r.traits||[]).slice(0,4).map(t=>`<div class="trait-item"><h4>${t.n}</h4><p>${(t.tx||[]).join(' ')}</p></div>`).join('')}</div>`;
  if(currentStep===5) renderStats();
  updatePreview();
}

