// ═══════════════════════════════════════
// STEP 5 — ATTRIBUTES
// ═══════════════════════════════════════
function setMethod(m){
  rollMethod=m;
  document.querySelectorAll('.method-btn').forEach((b,i)=>{
    b.classList.toggle('active',['roll4d6','standard','pointbuy','manual'][i]===m);
  });
  document.getElementById('roll-result').style.display=m==='roll4d6'?'flex':'none';
  document.getElementById('pb-info').style.display=m==='pointbuy'?'flex':'none';
  if(m==='roll4d6') doRoll();
  if(m==='standard'){
    const order=['STR','DEX','CON','INT','WIS','CHA'];
    order.forEach((s,i)=>pc.base_stats[s]=STANDARD_ARRAY[i]);
    renderStats();
  }
  if(m==='pointbuy'){
    STATS.forEach(s=>pc.base_stats[s]=8);
    pbPoints=27; renderStats();
  }
  if(m==='manual'){ renderStats(); }
}

function doRoll(){
  rollValues=[];
  for(let i=0;i<6;i++){
    const dice=[1,2,3,4].map(()=>Math.ceil(Math.random()*6));
    dice.sort((a,b)=>b-a);
    rollValues.push({val:dice[0]+dice[1]+dice[2], used:false});
  }
  rollValues.sort((a,b)=>b.val-a.val);
  selectedRoll=null;
  renderRollChips();
}

function renderRollChips(){
  const el=document.getElementById('roll-chips'); if(!el) return;
  el.innerHTML=rollValues.map((r,i)=>`
    <div class="roll-chip${r.used?' used':selectedRoll===i?' selected':''}"
      onclick="${r.used?'':'clickRollChip('+i+')'}">${r.val}</div>`).join('');
}

function clickRollChip(i){
  if(rollValues[i].used) return;
  selectedRoll=i; renderRollChips();
}

function assignRollToStat(stat){
  if(rollMethod==='roll4d6'&&selectedRoll!==null&&!rollValues[selectedRoll].used){
    pc.base_stats[stat]=rollValues[selectedRoll].val;
    rollValues[selectedRoll].used=true;
    selectedRoll=null;
    renderRollChips();
  } else if(rollMethod==='pointbuy'){
    // handled in stat input change
  }
  renderStats();
}

function renderStats(){
  const el=document.getElementById('stats-grid'); if(!el) return;
  el.innerHTML=STATS.map(s=>{
    const base=pc.base_stats[s]||10;
    const racial=(pc.race?.bonus?.[s])||0;
    const total=base+racial;
    const mStr=modVal(total);
    return `<div class="stat-box" onclick="assignRollToStat('${s}')">
      <div class="stat-name">${STAT_NAMES[s]}</div>
      <input class="stat-input" type="number" min="3" max="20" value="${base}"
        onchange="onStatChange('${s}',this.value)" onclick="event.stopPropagation()">
      ${racial?`<div class="stat-racial">+${racial} raza</div>`:''}
      <div class="stat-total">${total}</div>
      <div class="stat-mod">${mStr}</div>
    </div>`;
  }).join('');
  computeDerived();
  updatePreview();
}

function onStatChange(stat, val){
  const v=Math.max(3,Math.min(20,+val||10));
  if(rollMethod==='pointbuy'){
    // Recalculate points
    const oldV=pc.base_stats[stat];
    const oldCost=pbCost[Math.min(15,Math.max(8,oldV))]||0;
    const newCost=pbCost[Math.min(15,Math.max(8,v))]||0;
    const delta=newCost-oldCost;
    if(pbPoints-delta<0){ return; } // can't afford
    pbPoints-=delta;
    document.getElementById('pb-points').textContent=pbPoints;
  }
  pc.base_stats[stat]=v;
  renderStats();
}

function computeDerived(){
  const dex=effectiveStat('DEX'), con=effectiveStat('CON');
  const hd=+(pc.class_?.hd||8);
  const level=pc.nivel||1;
  const conMod=Math.floor((con-10)/2);
  pc.hp_max=hd+conMod+(level-1)*(Math.ceil(hd/2)+1+conMod);
  pc.hp_max=Math.max(1,pc.hp_max);
  pc.hp_curr=pc.hp_max;
  pc.ca=10+Math.floor((dex-10)/2);
  const total=STATS.reduce((s,k)=>s+effectiveStat(k),0);
  const dexMod=Math.floor((dex-10)/2);
  const initStr=(dexMod>=0?'+':'')+dexMod;
  const calcHp=document.getElementById('calc-hp');
  const calcCa=document.getElementById('calc-ca');
  const calcInit=document.getElementById('calc-init');
  const calcTotal=document.getElementById('calc-total');
  if(calcHp) calcHp.textContent=pc.hp_max;
  if(calcCa) calcCa.textContent=pc.ca;
  if(calcInit) calcInit.textContent=initStr;
  if(calcTotal) calcTotal.textContent=total;
}

// ═══════════════════════════════════════
// STEP 6 — SKILLS
// ═══════════════════════════════════════
function renderSkills(){
  const el=document.getElementById('skills-grid'); if(!el) return;
  const cls=pc.class_;
  const bgSkills=new Set(pc.background?.skills||[]);
  const clsSkills=new Set(cls?.skillChoices||[]);
  const maxChoose=cls?.nSkills||2;
  const chosenClass=SKILL_DEF.filter(s=>pc.skills[s.n]&&!bgSkills.has(s.n));
  const info=document.getElementById('skill-info');
  if(info) info.innerHTML=`<div class="bonus-chips">
    <span class="chip chip-purple">Elige ${maxChoose} pericias de clase</span>
    <span class="chip chip-green">+${bgSkills.size} de trasfondo (incluidas)</span>
    ${chosenClass.length?`<span class="chip chip-gold">${chosenClass.length}/${maxChoose} elegidas</span>`:''}
  </div>`;
  const prof=profBonus(pc.nivel||1);
  el.innerHTML=SKILL_DEF.map(sk=>{
    const isBg=bgSkills.has(sk.n);
    const isCls=clsSkills.has(sk.n);
    const isChosen=!!pc.skills[sk.n];
    const statVal=effectiveStat(sk.s);
    const baseMod=Math.floor((statVal-10)/2);
    const total=baseMod+(isChosen?prof:0);
    const totalStr=(total>=0?'+':'')+total;
    if(isBg){
      return `<div class="skill-row locked">
        <input type="checkbox" class="skill-check" checked disabled>
        <div class="skill-name">${sk.es} <span style="font-size:10px;color:var(--purple-b)">(trasfondo)</span></div>
        <span class="skill-stat">${sk.s}</span>
        <span class="skill-mod">${totalStr}</span>
      </div>`;
    }
    if(!isCls){
      return `<div class="skill-row" style="opacity:.4;cursor:not-allowed">
        <input type="checkbox" class="skill-check" disabled>
        <div class="skill-name">${sk.es}</div>
        <span class="skill-stat">${sk.s}</span>
        <span class="skill-mod">${totalStr}</span>
      </div>`;
    }
    return `<div class="skill-row${isChosen?' selected':''}" onclick="toggleSkill('${sk.n}',${maxChoose})">
      <input type="checkbox" class="skill-check" ${isChosen?'checked':''} onchange="toggleSkill('${sk.n}',${maxChoose})">
      <div class="skill-name">${sk.es}</div>
      <span class="skill-stat">${sk.s}</span>
      <span class="skill-mod">${totalStr}</span>
    </div>`;
  }).join('');
}

function toggleSkill(name, max){
  const bgSkills=new Set(pc.background?.skills||[]);
  if(bgSkills.has(name)) return;
  const cls=pc.class_;
  const clsSkills=new Set(cls?.skillChoices||[]);
  if(!clsSkills.has(name)) return;
  if(pc.skills[name]){
    delete pc.skills[name];
  } else {
    const curChosen=Object.keys(pc.skills).filter(s=>!bgSkills.has(s)).length;
    if(curChosen>=max){ setErr('err-6',`Solo puedes elegir ${max} pericias de clase.`); return; }
    pc.skills[name]=true;
  }
  clearErr('err-6');
  renderSkills();
}

// ═══════════════════════════════════════
// STEP 7 — SUMMARY
// ═══════════════════════════════════════
function renderSummary(){
  const el=document.getElementById('final-summary'); if(!el) return;
  computeDerived();
  const prof=profBonus(pc.nivel||1);
  const skillList=SKILL_DEF.filter(s=>pc.skills[s.n]).map(s=>{
    const v=effectiveStat(s.s);
    const base=Math.floor((v-10)/2);
    const total=base+prof;
    return `${s.es} ${total>=0?'+':''}${total}`;
  });
  const saveList=(pc.class_?.saves||[]).map(s=>{
    const v=effectiveStat(s);
    const base=Math.floor((v-10)/2);
    const total=base+prof;
    return `${STAT_NAMES[s]} ${total>=0?'+':''}${total}`;
  });
  el.innerHTML=`
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:24px">
      <!-- Identity -->
      <div>
        <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:10px">IDENTIDAD</div>
        <div style="font-family:'Cinzel Decorative',serif;font-size:24px;background:linear-gradient(135deg,var(--purple-b),var(--gold));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text">${pc.nombre}</div>
        <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--cream-m);letter-spacing:.5px;margin-top:4px">${pc.race?.n||'?'} · ${pc.class_?.n||'?'} · Nivel ${pc.nivel}</div>
        <div style="font-size:13px;color:var(--cream-m);margin-top:6px">${pc.background?.n||'?'} · ${pc.alignment}</div>
        ${pc.appearance?`<div style="font-size:13px;color:var(--cream-d);margin-top:8px;font-style:italic">${pc.appearance}</div>`:''}
      </div>
      <!-- Combat stats -->
      <div>
        <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:10px">ESTADÍSTICAS DE COMBATE</div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px">
          ${[['HP',pc.hp_max],['CA',pc.ca],['Prof','+'+prof],
             ['Ini',modVal(effectiveStat('DEX'))],
             ['XP',pc.xp],['Niv',pc.nivel]]
            .map(([l,v])=>`<div style="background:var(--bg3);border:1px solid var(--border);border-radius:2px;padding:8px;text-align:center">
              <div style="font-family:'Cinzel',serif;font-size:18px;color:var(--gold);font-weight:700">${v}</div>
              <div style="font-family:'Cinzel',serif;font-size:8px;color:var(--cream-m);letter-spacing:.5px;margin-top:2px">${l}</div>
            </div>`).join('')}
        </div>
      </div>
    </div>
    <!-- Stats grid -->
    <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:10px">ATRIBUTOS</div>
    <div style="display:grid;grid-template-columns:repeat(6,1fr);gap:8px;margin-bottom:20px">
      ${STATS.map(s=>{
        const v=effectiveStat(s);
        const base=pc.base_stats[s];
        const racial=(pc.race?.bonus?.[s])||0;
        return `<div style="background:var(--bg3);border:1px solid var(--border);border-radius:2px;padding:8px;text-align:center">
          <div style="font-family:'Cinzel',serif;font-size:18px;color:var(--gold);font-weight:700">${v}</div>
          <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--purple-b)">${modVal(v)}</div>
          <div style="font-family:'Cinzel',serif;font-size:8px;color:var(--cream-m);letter-spacing:.5px;margin-top:2px">${STAT_NAMES[s]}</div>
          ${racial?`<div style="font-size:9px;color:var(--green-b)">(${base}+${racial})</div>`:''}
        </div>`;
      }).join('')}
    </div>
    <!-- Skills & Saves -->
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px">
      <div>
        <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:8px">PERICIAS</div>
        ${skillList.map(s=>`<div style="font-size:13px;color:var(--cream-d);padding:3px 0;border-bottom:1px solid rgba(42,32,64,.4)">${s}</div>`).join('')||'<div style="font-size:13px;color:var(--cream-m);font-style:italic">Sin pericias</div>'}
      </div>
      <div>
        <div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:8px">SALVACIONES</div>
        ${saveList.map(s=>`<div style="font-size:13px;color:var(--cream-d);padding:3px 0;border-bottom:1px solid rgba(42,32,64,.4)">${s}</div>`).join('')||'<div style="font-size:13px;color:var(--cream-m);font-style:italic">Sin salvaciones de competencia</div>'}
      </div>
    </div>
    ${pc.backstory?`<div style="margin-top:20px"><div style="font-family:'Cinzel',serif;font-size:11px;color:var(--gold-d);letter-spacing:1px;margin-bottom:8px">TRASFONDO</div><div style="font-size:14px;color:var(--cream-d);line-height:1.6;font-style:italic">${pc.backstory}</div></div>`:''}`;
}

// ═══════════════════════════════════════
// PREVIEW (sidebar)
// ═══════════════════════════════════════
function updatePreview(){
  const nm=document.getElementById('prev-name');
  const cl=document.getElementById('prev-class');
  const al=document.getElementById('prev-align');
  const hp=document.getElementById('prev-hp');
  const ca=document.getElementById('prev-ca');
  const pf=document.getElementById('prev-prof');
  const name=document.getElementById('pc-name')?.value||'Sin nombre';
  if(nm) nm.textContent=name||'Sin nombre';
  const parts=[pc.race?.n||'?',pc.class_?.n||'?','Nivel '+(pc.nivel||1)];
  if(cl) cl.textContent=parts.join(' · ');
  if(al) al.textContent=pc.alignment;
  computeDerived();
  if(hp) hp.textContent=pc.hp_max;
  if(ca) ca.textContent=pc.ca;
  if(pf) pf.textContent='+'+profBonus(pc.nivel||1);
  const statsEl=document.getElementById('prev-stats');
  if(statsEl) statsEl.innerHTML=STATS.map(s=>{
    const v=effectiveStat(s);
    return `<div class="preview-stat">
      <div class="preview-stat-val">${v}</div>
      <div class="preview-stat-mod">${modVal(v)}</div>
      <div class="preview-stat-name">${s}</div>
    </div>`;
  }).join('');
}

// ═══════════════════════════════════════
// SAVE
// ═══════════════════════════════════════
async function saveCharacter(){
  clearErr('err-7');
  document.getElementById('suc-7').textContent='';
  if(!currentUser){ setErr('err-7','No has iniciado sesión.'); return; }
  computeDerived();
  const btn=document.getElementById('btn-save');
  btn.disabled=true; btn.innerHTML='<span class="spinner"></span> Guardando...';

  const saveProfs={};
  (pc.class_?.saves||[]).forEach(s=>saveProfs[s]=true);

  const char={
    campaign_id: null, // unassigned until joined
    player_pin:  null, // no pin — auth based
    user_id:     currentUser.id,
    nombre:      pc.nombre,
    clase:       pc.class_?.n||'',
    raza:        pc.race?.n||'',
    trasfondo:   pc.background?.n||'',
    nivel:       pc.nivel||1,
    xp:          pc.xp||0,
    str:         effectiveStat('STR'),
    dex:         effectiveStat('DEX'),
    con:         effectiveStat('CON'),
    int_:        effectiveStat('INT'),
    wis:         effectiveStat('WIS'),
    cha:         effectiveStat('CHA'),
    hp_max:      pc.hp_max,
    hp_curr:     pc.hp_curr,
    ca:          pc.ca,
    alignment:   pc.alignment,
    equipo:      [],
    habilidades: [],
    skills:      pc.skills,
    skill_overrides:{},
    save_profs:  saveProfs,
    dinero:      0,
    backstory:   pc.backstory||'',
    appearance:  pc.appearance||'',
  };

  let result;
  if(editingId){
    result = await sb.from('characters').update(char).eq('id',editingId).select().single();
  } else {
    result = await sb.from('characters').insert(char).select().single();
  }

  btn.disabled=false; btn.textContent='💾 Guardar personaje';
  if(result.error){
    setErr('err-7','Error al guardar: '+result.error.message);
    return;
  }
  document.getElementById('suc-7').textContent=`✓ ${pc.nombre} guardado correctamente.`;
  setTimeout(()=>{ window.location.href='login.html'; }, 1500);
}

